#include<bits/stdc++.h>
#define LL long long
#define pb push_back
using namespace std;
const int N = 205;
LL n,m,dp[N][N],c[N][N];bool b[N],flag;
int main(){
    cin>>n>>m;
    memset(dp,0x3f,sizeof(dp));
    for(int i=1;i<=n;i++)dp[i][i]=0;
    for(int i=1;i<=m;i++){
        LL x,y,z;cin>>x>>y>>z;
        dp[x][y]=min(dp[x][y],z),dp[y][x]=min(dp[y][x],z);
    }
    for(int k=1;k<=n;k++)for(int i=1;i<=n;i++)for(int j=1;j<=n;j++){
        if(k==i||k==j||i==j||dp[i][k]+dp[k][j]>dp[i][j])continue;
        if(dp[i][k]+dp[k][j]==dp[i][j])c[i][j]=0;
        else dp[i][j]=dp[i][k]+dp[k][j],c[i][j]=k;
    }
    for(int i=1;i<=n;i++)for(int j=1;j<=n;j++)b[c[i][j]]=1;
    for(int i=1;i<=n;i++)if(b[i]){flag=1;cout<<i<<" ";}
    if(!flag)cout<<"No important cities.";cout<<"\n";
    return 0;
}
